import React from "react";
import { Avatar, Button, Divider, List, Popover, Skeleton } from "antd";
import Text from "antd/es/typography/Text";
import { useSearchProjects } from "utils/project";
import { PopoverProps } from "antd/es/popover";
import { Link } from "react-router-dom";
import { useDoProject } from "utils/use-do-project";

export const ProjectPopover = (props: PopoverProps) => {
  const { data: projects, isLoading } = useSearchProjects();
  const pinnedProjects = projects?.filter((project) => project.pin);
  const projectId = 1;
  const currentProject = projects?.find((project) => project.id === projectId);
  const { startCreate } = useDoProject();

  const content = (
    <div style={{ minWidth: "305px" }}>
      {currentProject ? (
        <>
          <Text type={"secondary"}>本项目</Text>
          <List>
            <List.Item>
              <Skeleton avatar={true} title={false} loading={isLoading} active>
                <List.Item.Meta
                  title={<Button type={'link'}>{currentProject.name}</Button>}
                  description={currentProject.organization}
                />
              </Skeleton>
            </List.Item>
          </List>
        </>
      ) : null}

      <>
        <Text type={"secondary"}>收藏项目</Text>
        <List>
          {pinnedProjects?.map((project) => (
            <List.Item key={project.id}>
              <Skeleton avatar={true} title={false} loading={isLoading} active>
                <List.Item.Meta
                  title={<a href="https://ant.design">{project.name}</a>}
                  description={project.organization}
                />
              </Skeleton>
            </List.Item>
          ))}
        </List>
      </>

      <Divider />
      <a onClick={startCreate}>创建项目</a>
      <Divider />
      <Link style={{ fontWeight: "bold" }} to={"/projects"}>
        查看全部项目
      </Link>
    </div>
  );

  return (
    <Popover placement={"bottom"} content={content} {...props}>
      项目
    </Popover>
  );
};
