import { useProjectIdInUrl, useSearch } from "../../utils/url";
import { useReorderTask, useSearchTasks, useTask } from "../../utils/task";
import { useReorderKanban } from "../../utils/kanban";
import { DropResult } from "react-beautiful-dnd";
import { useHttp } from "utils/http";
import { useQuery, useQueryClient } from "react-query";
import { Task } from "types/task";
import { Kanban } from "types/kanban";

export const useQueries = () => useSearch(["taskName", "processorId", "epicId", "tagIds"]);

export const useDragEnd = () => {
  const { data: kanbans } = useKanbans();
  const { data: allTasks = [] } = useTasks();
  const { mutate: reorderKanban } = useReorderKanban();
  const { mutate: reorderTask } = useReorderTask();
  const getTask = ({
                     kanbanId,
                     index
                   }: {
    kanbanId: number;
    index: number;
  }) => {
    const tasksInThisKanban =
      allTasks?.filter((task) => task.kanbanId === kanbanId) || [];
    return tasksInThisKanban[index];
  };

  const callback = async ({ source, destination, type }: DropResult) => {
    if (!destination) {
      return;
    }

    // 如果 type 是 'COLUMN' 的话，说明在移动看板
    if (type === "COLUMN") {
      const fromId = kanbans?.[source.index].id;
      const toId = kanbans?.[destination.index].id;
      if (!fromId || !toId || fromId === toId) {
        return;
      }
      const type = destination.index > source.index ? "after" : "before";
      await reorderKanban({ fromId, referenceId: toId, type });
    }

    // 如果 type 是 'ROW' 的话，说明在移动Task
    if (type === "ROW") {
      const fromKanbanId = +source.droppableId.split("kanban-id")[1];
      const toKanbanId = +destination.droppableId.split("kanban-id")[1];
      const fromTask = getTask({
        kanbanId: fromKanbanId,
        index: source.index
      });
      const toTask = getTask({
        kanbanId: toKanbanId,
        index: destination.index
      });
      // TODO server 也要加上这个判断
      if (fromTask?.id === toTask?.id) {
        return;
      }
      const type =
        fromKanbanId === toKanbanId && destination.index > source.index
          ? "after"
          : "before";
      await reorderTask({
        type,
        fromId: fromTask.id,
        referenceId: toTask?.id,
        fromKanbanId,
        toKanbanId
      });
    }
  };

  return callback;
};

export const useTaskSearch = () => {
  const queryClient = useQueryClient();
  const params = ({
    ...useSearch(["taskName", "processorId", "epicId", "tagIds"])[0],
    projectId: useProjectIdInUrl()
  });
  const queryKey = ["tasks", params];
  return {
    params,
    queryKey,
    cacheData: queryClient.getQueryData<Task[]>(queryKey)
  };
};

export const useTasks = () => {
  const params = useTaskSearch().params;
  return useSearchTasks({
    ...params,
    taskName: undefined,
    name: params.taskName
  });
};

export const useKanbans = () => {
  const client = useHttp();
  const { params, queryKey } = useKanbanSearch();
  return useQuery<Kanban[]>(queryKey, () => client("kanbans", { data: params }));
};

export const useKanbanSearch = () => {
  const params = {
    projectId: useProjectIdInUrl()
  };
  const queryKey = ["kanbans", params];
  return {
    params,
    queryKey
  };
};

