/** @jsx jsx */
import { css, jsx } from "@emotion/react";
import React from "react";
import { useEpicsInProject } from "../../utils/epic";
import { useDocumentTitle } from "../../utils";
import { useSearchTasks } from "utils/task";
import { useProjectIdInUrl, useProjectInUrl } from "utils/url";
import { Button, List } from "antd";
import { Row } from "components/lib";
import { DoEpicScreen } from "screens/epic/create-epic";
import { useEpicPatch } from "screens/epic/use-epic-patch";
import dayjs from "dayjs";
import { Link } from "react-router-dom";

export const EpicScreen = () => {
  useDocumentTitle("任务组列表");
  const { data: epics } = useEpicsInProject();
  const projectId = useProjectIdInUrl();
  const { data: tasks } = useSearchTasks({ projectId: +projectId });
  const { data: project } = useProjectInUrl();
  const { startCreate } = useEpicPatch();

  return (
    <div
      style={{
        width: "100%",
        display: "flex",
        flexDirection: "column",
        paddingBottom: "1rem",
      }}
    >
      <DoEpicScreen />
      <Row between={true}>
        <h1>{project?.name}任务组</h1>
        <Button onClick={startCreate}>创建任务组</Button>
      </Row>
      <List
        css={css`
          ::-webkit-scrollbar {
            display: none;
          }
        `}
        style={{ overflow: "scroll" }}
        itemLayout="vertical"
        dataSource={epics}
        renderItem={(epic) => (
          <List.Item>
            <List.Item.Meta
              title={epic.name}
              description={
                <div>
                  <div>开始时间: {dayjs(epic.start).format("YYYY-MM-DD")}</div>
                  <div>结束时间: {dayjs(epic.end).format("YYYY-MM-DD")}</div>
                  <div>{epic.note}</div>
                </div>
              }
            />
            <div style={{ marginBottom: "2rem" }}>
              {tasks
                ?.filter((task) => task.epicId === epic.id)
                .map((task) => (
                  <div key={task.id}>
                    <Link
                      to={`/projects/${projectId}/kanban?editingTaskId=${task.id}`}
                    >
                      {task.name}
                    </Link>
                  </div>
                ))}
              {/*<CreateTask kanbanId={kanbans?.[0].id} epicId={epic.id} />*/}
            </div>
          </List.Item>
        )}
      ></List>
    </div>
  );
};
