/** @jsx jsx */
import { css, jsx } from "@emotion/react";
import React, { CSSProperties } from "react";
import { Form, Input } from "antd";
import { useSearch } from "utils/url";
import { useUsers } from "utils/user";
import { UserSelect } from "components/user-select";

export type ProjectSearchPanelProps = {
  style?: CSSProperties;
};

export const SearchPanel: React.FC<ProjectSearchPanelProps> = ({}) => {
  // 这就是解耦的过程
  let [searchParams, setSearchParams] = useSearch(["name", "personId"]);
  const { data: users } = useUsers();
  return (
    <Form
      layout={"inline"}
      style={{ marginBottom: "2rem" }}
    >
      <Form.Item>
        <Input
          css={css`
          width: 15rem;
        `}
          allowClear={true}
          value={searchParams.name}
          onChange={(evt) => setSearchParams({ name: evt.target.value })}
          placeholder={"项目名"}
        />
      </Form.Item>
      <UserSelect
        defaultOptionName={"负责人"}
        value={searchParams.personId}
        onChange={(value) => setSearchParams({ personId: value })}
      />
    </Form>
  );
};
