import { useHttp } from "./http";
import { useQuery } from "react-query";
import { TaskType } from "../types/task-type";
import bugImg from 'assets/bug.svg'
import taskImg from 'assets/task.svg'

export const useTaskTypeInfo = () => {
  const { data: taskTypes = [] } = useTaskTypes();
  return (taskTypeId: number) => {
    const name = taskTypes.find(item => item.id === taskTypeId)?.name;
    return ({
      name,
      iconUrl: name === "bug" ? bugImg : taskImg
    });
  };
};

export const useTaskTypes = () => {
  const client = useHttp();
  return useQuery<TaskType[]>({
    queryKey: ["taskTypes"],
    queryFn: () => {
      return client("taskTypes");
    }
  });
};
