import { useHttp } from "./http";
import {
  useMutation,
  useQuery, useQueryClient
} from "react-query";
import { Task } from "../types/task";
import { reorder, useKanban } from "./kanban";
import { Raw } from "../types";
import { useAddConfig, useConfig, useDeleteConfig, useEditConfig } from "utils/use-query-default-options";
import { useTaskSearch } from "screens/kanban/util";

export const useSearchTasks = (param?: object) => {
  const client = useHttp();
  return useQuery<Task[], Error>({
    queryKey: ["tasks", param],
    queryFn: () => {
      return client("tasks", { data: param });
    }
  });
};

export const useEditTask = () => {
  const client = useHttp();
  return useMutation(
    (params: Partial<Task>) =>
      client(`tasks/${params.id}`, {
        data: params,
        method: "PATCH"
      }),
    useEditConfig(useTaskSearch().queryKey)
  );
};

export const useTask = (id: Raw) => {
  const client = useHttp();
  return useQuery<Task>(
    ["task", { id }],
    () => client(`tasks/${id}`),
    {
      enabled: !!id
    }
  );
};

export const useDeleteTask = () => {
  const client = useHttp();
  return useMutation(
    (id: number) =>
      client(
        `tasks/${id}`,
        {
          method: "DELETE"
        }),
    useDeleteConfig(useTaskSearch().queryKey)
  );
};

export const useCreateTask = () => {
  const client = useHttp();
  return useMutation(
    (params: Partial<Task>) =>
      client(`tasks`, {
        data: params,
        method: "POST"
      }),
    useAddConfig(useTaskSearch().queryKey)
  );
};

export type SortProps = {
  type: "before" | "after";
  referenceId: number;
  fromId: number;
};

export const useReorderTask = () => {
  const client = useHttp();
  return useMutation(
    (params: { fromKanbanId: number; toKanbanId: number } & SortProps) =>
      client(`tasks/reorder`, {
        data: params,
        method: "POST"
      }),
    useConfig(useTaskSearch().queryKey, (target, old) => {
        console.log(old);
        // TODO 这个要删掉啊
        const list = reorder({ list: [...old], ...target }) as Task[];
        const theItem = list.find(task => task.id === target.fromId);
      console.log(target);
      if (theItem) {
          list[list.indexOf(theItem)] = { ...theItem, kanbanId: target.toKanbanId };
        }
        return list;
      }
    )
  );
};


