import { ColumnsType } from "antd/es/table";
import { Project } from "types/project";
import { Pin } from "components/pin";
import React from "react";
import { useDeleteProject, useEditProject } from "utils/project";
import { useUsers } from "utils/user";
import dayjs from "dayjs";
import { Dropdown, Menu, Modal } from "antd";
import { Link } from "react-router-dom";
import { useDoProject } from "utils/use-do-project";

const { confirm } = Modal;

export const useColumns = () => {
  const { mutateAsync: editProject } = useEditProject();
  const { mutateAsync: deleteProject } = useDeleteProject();
  const { startEdit } = useDoProject();
  const { data: users } = useUsers();

  const pin = (id: number) => (pinned: boolean) =>
    editProject({ pin: pinned, id });

  const remove = (id: number) => () =>
    confirm({
      title: "确定删除这个项目吗？",
      content: "点击确定删除",
      okText: "确定",
      onOk() {
        deleteProject(id);
      }
    });

  return [
    {
      width: "8rem",
      title: <Pin disabled={true} checked={true} />,
      render(value, project) {
        return <Pin checked={project.pin} onCheckedChange={pin(project.id)} />;
      }
    },
    {
      width: "15rem",
      title: "名称",
      sorter: (a, b) => a.name.localeCompare(b.name),
      render(value, project) {
        return <Link to={String(project.id)}>{project.name}</Link>;
      }
    },
    {
      width: "15rem",
      title: "部门",
      render(value, project) {
        return <span>{project.organization}</span>;
      }
    },
    {
      width: "15rem",
      title: "负责人",
      render(value, project) {
        return (
          <div>
            <a>{users?.find((user) => user.id === project.personId)?.name}</a>
          </div>
        );
      }
    },
    {
      width: "15rem",
      title: "创建时间",
      render(value, project) {
        return (
          <div>
            <span>
              {project.created
                ? dayjs(project.created).format("YYYY-MM-DD")
                : "无"}
            </span>
          </div>
        );
      }
    },
    {
      width: "15rem",
      render(value, project) {
        return (
          <Dropdown
            overlay={
              <Menu>
                <Menu.Item key="logout">
                  <a onClick={() => startEdit(project.id)}>编辑</a>
                </Menu.Item>
                <Menu.Item key="delete">
                  <a onClick={remove(project.id)}>删除</a>
                </Menu.Item>
              </Menu>
            }
          >
            <a>...</a>
          </Dropdown>
        );
      }
    }
  ] as ColumnsType<Project>;
};
