import React from "react";
import { Rate } from "antd";
import { RateProps } from "antd/es/rate";

export interface PinProps extends RateProps {
  checked: boolean;
  onCheckedChange?: (param: boolean) => void;
}

export const Pin: React.FC<PinProps> = function ({
  checked,
  onCheckedChange,
  ...props
}) {
  return (
    <Rate
      style={{ color: "rgb(255, 171, 0)" }}
      defaultValue={checked ? 1 : 0}
      count={1}
      value={checked ? 1 : 0}
      onChange={(num) => onCheckedChange?.(!!num)}
      {...props}
    />
  );
};
