const toNumberWithArray = (value: unknown) =>
  !value ? 0 : Array.isArray(value) ? value.map(Number) : Number(value);

export type BaseIdSelectProp = Omit<
  React.ComponentProps<typeof Select>,
  "value" | "onChange" | "options" | "mode"
> & {
  options?: { name: string; id: number }[];
  defaultOptionName?: string;
};

export type SingleIdProp = BaseIdSelectProp & {
  value?: Raw | null | undefined;
  onChange?: (value?: number) => void;
  mode?: "single";
};

export type MultipleIdProp = BaseIdSelectProp & {
  value?: Raw[] | null | undefined;
  onChange?: (value?: number[]) => void;
  mode: "multiple";
};

export function IdSelect(props: MultipleIdProp | SingleIdProp) {
  const { value, onChange, defaultOptionName, options, mode, ...rest } = props;

  return (
    <Select
      placeholder={defaultOptionName}
      value={toNumberWithArray(value)}
      mode={mode === "multiple" ? "multiple" : undefined}
      onChange={(value) => {
        props.mode === "multiple"
          ? props.onChange?.(value ? (value as Raw[]).map(Number) : undefined)
          : props.onChange?.(value ? Number(value) : undefined);
      }}
      {...rest}
    >
      {defaultOptionName ? (
        <Select.Option value={0}>{defaultOptionName}</Select.Option>
      ) : null}
      {options?.map((option) => (
        <Select.Option key={option.id} value={option.id}>
          {option.name}
        </Select.Option>
      ))}
    </Select>
  );
}
