/** @jsx jsx */
import React from "react";
import { css, jsx } from "@emotion/react";
import { useTags } from "../utils/tag";
import { IdSelect, MultipleIdProp } from "./id-select";

type Props = Omit<MultipleIdProp, "mode">;

export const TagSelect = ({ value, ...props }: Props) => {
  const { data: tags = [] } = useTags();

  return (
    <IdSelect
      css={css`
        min-width: 13rem;
      `}
      {...props}
      value={value || []}
      placeholder={"标签"}
      options={tags}
      mode={"multiple"}
    />
  );
};
