import React from "react";
import { Navigate, Route, Routes } from "react-router-dom";
import { ProjectListScreen } from "screens/project-list";
import { ProjectScreen } from "screens/project";
import { PageHeader } from "components/header";
import { ProjectModalScreen } from "screens/project-create";
import styled from "@emotion/styled";
import { AuthenticatedAppProviders } from "./context";
import { PatchTaskScreen } from "./screens/task-patch";

const App = styled.div`
  display: grid;
  grid-template-rows: 6rem calc(100vh - 6rem);
`;

export const AuthenticatedApp = () => {
  return (
    // errorboundary 会替换出错的组件
    // 如果是header什么的出了错误，就直接卸载所有的组件，注意如果 /projects 有问题，就会触发这里
    // 而不是里面，因为header也请求 /projects 的
    <AuthenticatedAppProviders>
      <App>
        <PageHeader />
        {/*为了简单，先删除, 如果app内部出了错误，就继续展示header什么的，只是在出错误的地方显示错误*/}
        {/*<ErrorBoundary FallbackComponent={ErrorFallback}>*/}
        <Routes>
          <Route path="/projects" element={<ProjectListScreen />} />
          <Route path="/projects/:projectId/*" element={<ProjectScreen />} />
          <Navigate to="/projects" replace={true} />
        </Routes>
        <ProjectModalScreen />
        <PatchTaskScreen />
        {/*</ErrorBoundary>*/}
      </App>
    </AuthenticatedAppProviders>
  );
};
