import { useEffect, useRef, useState } from "react";
import { json } from "msw/lib/types/context";

// any vs unknown: https://stackoverflow.com/a/57356103
const isFalsy = (value: unknown) => {
  return value === 0 ? true : !!value;
};

const isVoid = (value: unknown) =>
  value === undefined || value === null || value === "";

export const keys = <O>(o: O) => Object.keys(o) as (keyof O)[];

// 不要用 object: https://github.com/microsoft/TypeScript/issues/21732
export const cleanObject = <T extends object>(object?: T) => {
  const result = { ...object };
  keys(result).forEach((key) => {
    if (isVoid(result[key])) {
      delete result[key];
    }
  });
  return result as T;
};

export const useMount = (fn: () => void) => {
  // eslint-disable-next-line
  useEffect(fn, []);
};

// TODO 每次无限循环都是因为这个useDebounce呀
// 外面传进来的值必须要用useMemo，指定基本类型为依赖
export const useDebounce = <T>(value: T, delay = 500) => {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => {
      clearTimeout(handler);
    };
  }, [value, delay]);

  return debouncedValue;
};

export const useArray = <T>(initialState: T[]) => {
  const [value, setValue] = useState(initialState);
  return {
    value,
    setValue,
    add: (item: T) => setValue([...value, item]),
    clear: () => setValue(() => []),
    removeIndex: (index: number) =>
      setValue((v) => {
        const copy = v.slice();
        copy.splice(index, 1);
        return copy;
      }),
  };
};

export const useDocumentTitle = (title: string, retainOnUnmount = true) => {
  // TODO 用这个例子讲 useRef
  const defaultTitle = useRef(document.title);

  useEffect(() => {
    document.title = title;
  }, [title]);

  useMount(() => {
    return () => {
      if (!retainOnUnmount) {
        document.title = defaultTitle.current;
      }
    };
  });
};

export const subset = <O extends object, K extends keyof O>(
  obj: O,
  keys: K[]
) =>
  Object.fromEntries(
    Object.entries(obj).filter(([key]: K[]) => keys.includes(key))
  ) as Pick<O, K>;

export const toValidString = (value: unknown) =>
  isVoid(value) ? "" : String(value);

export const tryParseJSON = (jsonString: unknown) => {
  console.log(123);
  if (typeof jsonString !== "string") {
    return jsonString;
  }
  try {
    const o = JSON.parse(jsonString);
    if (o && typeof o === "object") {
      return o;
    }
  } catch (e) {}
  return jsonString;
};

export const remove0 = (value: number) => (value === 0 ? undefined : value);
