import React from "react";
import { Table } from "antd";
import { useColumns } from "screens/project-list/use-columns";
import { TableProps } from "antd/es/table";
import { Project } from "types/project";

type ListProps = TableProps<Project>;

export const List: React.FC<ListProps> = ({ dataSource, ...rest }) => {
  const columns = useColumns();

  return (
    <Table
      rowKey={'id'}
      pagination={false}
      columns={columns}
      dataSource={dataSource}
      {...rest}
    />
  );
};
