import { useSearch } from "utils/url";
import { useHttp } from "utils/http";
import { useQuery } from "react-query";
import { Task } from "types/task";
import { useTaskSearch } from "screens/kanban/util";

export const useProjectsSearchParams = () => useSearch(["name", "personId"])[0];

export const useProjectsQueryKey = () => ["projects", useProjectsSearchParams()];

export const useProjects = () => {
  const client = useHttp();
  const params = useTaskSearch().params;

  return useQuery<Task[]>(useProjectsQueryKey(), () => {
    return client("tasks", { data: params });
  });
};

