import React, { useMemo } from "react";
import { Button, Input } from "antd";
import { UserSelect } from "../../components/user-select";
import { EpicSelect } from "../../components/epic-select";
import { Row } from "../../components/lib";
import { useProjectInUrl } from "../../utils/url";
import { TagSelect } from "../../components/tag-select";
import { useQueries } from "screens/kanban/util";

export const SearchPanel = () => {
  const [searchParams, setSearchParams, reset] = useQueries();

  return (
    <>
      <Row gap={true}>
        <Input
          style={{ width: "20rem" }}
          placeholder={"任务名"}
          value={searchParams.taskName}
          onChange={(evt) =>
            setSearchParams({
              taskName: evt.target.value,
            })
          }
        />
        <EpicSelect
          placeholder={"任务组"}
          value={searchParams.epicId}
          onChange={(value) => setSearchParams({ epicId: value })}
        />
        <UserSelect
          defaultOptionName={'经办人'}
          value={searchParams.processorId}
          onChange={(value) => {
            setSearchParams({ processorId: value })
          }}
        />
        <TagSelect
          value={searchParams.tagIds}
          onChange={(value) => setSearchParams({ tagIds: value })}
        />
        <Button onClick={reset}>清除筛选器</Button>
      </Row>
    </>
  );
};
