import React from "react";
import { Avatar, List, Popover, Skeleton } from "antd";
import Text from "antd/es/typography/Text";
import { PopoverProps } from "antd/es/popover";
import { useUsers } from "utils/user";

export const UserPopover = (props: PopoverProps) => {
  const { data: users, isLoading } = useUsers();

  const content = (
    <div style={{ minWidth: "305px" }}>
      <Text type={"secondary"}>您的团队</Text>
      <List>
        {users?.map((user) => (
          <List.Item key={user.id}>
            <Skeleton avatar={true} title={false} loading={isLoading} active>
              <List.Item.Meta
                title={<a href="https://ant.design">{user.name}</a>}
                description={user.organization}
              />
            </Skeleton>
          </List.Item>
        ))}
      </List>
    </div>
  );

  return (
    <Popover placement={"bottom"} content={content} {...props}>
      用户
    </Popover>
  );
};
