import { useHttp } from "./http";
import {
  useMutation,
  useQuery
} from "react-query";
import { Kanban } from "../types/kanban";
import { Raw } from "types";
import { useAddConfig, useConfig, useDeleteConfig, useEditConfig } from "utils/use-query-default-options";
import { useKanbanSearch } from "screens/kanban/util";

export type SortProps = {
  type: "before" | "after";
  referenceId: number;
  fromId: number;
};

export const useKanban = (id?: Raw) => {
  const client = useHttp();
  return useQuery<Kanban>(
    ["kanban", { id }],
    () => client(`kanbans/${id}`),
    {
      enabled: !!id
    });
};

export const useCreateKanban = () => {
  const client = useHttp();
  return useMutation(
    (params: Partial<Kanban>) =>
      client(`kanbans`, {
        data: params,
        method: "POST"
      }),
    useAddConfig(useKanbanSearch().queryKey)
  );
};

export const useEditKanban = () => {
  const client = useHttp();
  return useMutation(
    (params: Partial<Kanban>) =>
      client(`kanbans/${params.id}`, {
        data: params,
        method: "PATCH"
      }),
    useEditConfig(useKanbanSearch().queryKey)
  );
};

export const useDeleteKanban = () => {
  const client = useHttp();
  return useMutation(
    (id: number) =>
      client(
        `kanbans/${id}`,
        {
          method: "DELETE"
        }),
    useDeleteConfig(useKanbanSearch().queryKey)
  );
};

export const useReorderKanban = () => {
  const client = useHttp();
  return useMutation(
    (params: SortProps) =>
      client(`kanbans/reorder`, {
        data: params,
        method: "POST"
      }),
    useConfig(useKanbanSearch().queryKey, (target, old) => {
        console.log(target, 'kanban');
        return reorder({ list: [...old], ...target });
      }
    )
  );
};

// TODO 别忘了把这个改成纯函数，这样使用的时候就不用复制了
export const reorder = ({
                          fromId,
                          type,
                          referenceId,
                          list
                        }: {
  list: { id: number }[];
  fromId: number;
  type: "after" | "before";
  referenceId: number;
}) => {
  const movingItemIndex = list.findIndex((item) => item.id === fromId);
  if (!referenceId) {
    return insertAfter([...list], movingItemIndex, list.length - 1);
  }
  const targetIndex = list.findIndex((item) => item.id === referenceId);
  const insert = type === "after" ? insertAfter : insertBefore;
  const result = insert([...list], movingItemIndex, targetIndex);
  return result;
};

const insertBefore = (list: unknown[], from: number, to: number) => {
  const toItem = list[to];
  const removedItem = list.splice(from, 1)[0];
  const toIndex = list.indexOf(toItem);
  list.splice(toIndex, 0, removedItem);
  return list;
};

const insertAfter = (list: unknown[], from: number, to: number) => {
  const toItem = list[to];
  const removedItem = list.splice(from, 1)[0];
  const toIndex = list.indexOf(toItem);
  list.splice(toIndex + 1, 0, removedItem);
  return list;
};
