/** @jsx jsx */
import { css, jsx } from "@emotion/react";
import React from "react";
import { List } from "screens/project-list/list";
import { SearchPanel } from "screens/project-list/search-panel";
import { LoadingOutlined } from "@ant-design/icons";
import { useDocumentTitle } from "utils";
import { Button, Typography } from "antd";
import { Container, Row } from "components/lib";
import { useSearchProjects } from "utils/project";
import { useSearch } from "utils/url";
import { useDoProject } from "utils/use-do-project";

const { Text, Title } = Typography;

const antIcon = <LoadingOutlined style={{ fontSize: 24 }} spin />;

export const ProjectListScreen = () => {
  useDocumentTitle("项目列表");

  const { startCreate } = useDoProject();
  let [searchParams] = useSearch(["name", "personId"]);
  const { data: list, isLoading, error } = useSearchProjects(searchParams);

  return (
    <Container>
      <Row marginBottom={2} between={true}>
        <Title>项目列表</Title>
        <Button onClick={startCreate}>创建项目</Button>
      </Row>
      <SearchPanel/>
      {error ? <Text type="danger">{error.message}</Text> : null}
      <List
        loading={{
          spinning: isLoading,
          indicator: antIcon
        }}
        dataSource={list || []}
      />
    </Container>
  );
};
