import React from "react";
import { DragDropContext } from "react-beautiful-dnd";
import { KanbanColumn } from "./kanban-column";
import { Drag, Drop, DropChild } from "../../components/dnd";
import { CreateKanban } from "./create-kanban";
import { useDocumentTitle } from "../../utils";
import { SearchPanel } from "./search-panel";
import { useDragEnd, useKanbans, useKanbanSearch, useTasks } from "./util";
import { useProjectInUrl } from "utils/url";
import { Spin } from "antd";

export const KanbanScreen = () => {
  useDocumentTitle("看板列表");
  const { data: kanbans, isLoading: kanbanLoading } = useKanbans();
  const { isLoading: taskLoading } = useTasks();
  const onDragEnd = useDragEnd();
  const { data: project } = useProjectInUrl();

  return (
    <div style={{ display: "flex", flexDirection: "column", width: "100%" }}>
      <h1>{project?.name}看板</h1>
      <SearchPanel />
      {!taskLoading && !kanbanLoading ? (
        <div
          style={{
            display: "flex",
            flex: 1,
            overflowX: "scroll",
            marginTop: "2rem",
            paddingBlock: "2rem",
          }}
        >
          <DragDropContext onDragEnd={onDragEnd}>
            <Drop type="COLUMN" direction={"horizontal"} droppableId={"kanban"}>
              <DropChild style={{ display: "flex" }}>
                {kanbans?.map((kanban, index) => (
                  // key 必须是id，index必须是连续的所以必须是index
                  <div
                    key={kanban.id}
                    style={{
                      marginRight: "2rem",
                      display: "flex",
                      overflow: "hidden",
                    }}
                  >
                    <Drag
                      key={kanban.id}
                      draggableId={"kanban" + kanban.id}
                      index={index}
                    >
                      <KanbanColumn key={kanban.name} kanban={kanban} />
                    </Drag>
                  </div>
                ))}
              </DropChild>
            </Drop>
            {/*必须放在drop外面，才能让placeholder撑住*/}
            <CreateKanban />
          </DragDropContext>
        </div>
      ) : (
        <Spin style={{ marginTop: "10rem" }} size={"large"} />
      )}
    </div>
  );
};
