import { useHttp } from "utils/http";
import { Project } from "types/project";
import { useMutation, useQuery, useQueryClient } from "react-query";
import { Raw } from "types";
import { useAddConfig, useDeleteConfig, useEditConfig } from "utils/use-query-default-options";
import { useProjectsQueryKey } from "screens/project-list/util";

export const useSearchProjects = (params?: Partial<Project>) => {
  const client = useHttp();
  return useQuery<Project[], Error>(
    ["projects", params],
    () => client("projects", { data: params })
  );
};

export const useProject = (id?: Raw) => {
  const client = useHttp();
  return useQuery<Project>(
    ["project", id],
    () => client(`projects/${id}`),
    {
      enabled: !!id
    });
};

export const useEditProject = () => {
  const client = useHttp();
  return useMutation(
    (params: Partial<Project>) =>
      client(`projects/${params.id}`, {
        data: params,
        method: "PATCH"
      }),
    // 这个是对的啊！！！ 其他的不对啊
    useEditConfig(useProjectsQueryKey())
  );
};

export const useCreateProject = () => {
  const client = useHttp();
  return useMutation(
    (params: Partial<Project>) =>
      client(`projects`, {
        data: params,
        method: "POST"
      }),
    useAddConfig(useProjectsQueryKey())
  );
};

export const useDeleteProject = () => {
  const client = useHttp();
  return useMutation(
    (id: number) =>
      client(
        `projects/${id}`,
        {
          method: "DELETE"
        }),
    useDeleteConfig(useProjectsQueryKey())
  );
};
