import React, { useEffect } from "react";
import { Input, Modal, Form, Button } from "antd";
import { useEditTask, useTask } from "../../utils/task";
import { UserSelect } from "../../components/user-select";
import { TagSelect } from "components/tag-select";
import { TypeSelect } from "components/type-select";
import { useForm } from "antd/es/form/Form";
import { useTaskPatch } from "screens/task-patch/use-task-patch";
import { EpicSelect } from "components/epic-select";

const layout = {
  labelCol: { span: 8 },
  wrapperCol: { span: 16 },
};

export const PatchTaskScreen = () => {
  const { editingId, close } = useTaskPatch();
  const { data: task } = useTask(editingId);
  const { mutateAsync: editTask, isLoading } = useEditTask();
  const [form] = useForm();

  useEffect(() => {
    form.setFieldsValue(task);
  }, [task]);

  return (
    <Modal
      bodyStyle={{ display: "flex", justifyContent: "center" }}
      okText={"确认"}
      cancelText={"取消"}
      confirmLoading={isLoading}
      title={"编辑任务"}
      visible={!!editingId}
      onCancel={() => {
        close();
        form.resetFields();
      }}
      onOk={() => {
        const newTask = form.getFieldsValue();
        editTask({ ...newTask, id: editingId }).then(close);
      }}
    >
      <Form
        {...layout}
        name="basic"
        initialValues={task}
        onFinish={(values) => {
          console.log("Success:", values);
        }}
        form={form}
      >
        <Form.Item
          label="任务名"
          name="name"
          rules={[{ required: true, message: "请输入任务名" }]}
        >
          <Input />
        </Form.Item>
        <Form.Item label="标签" name="tagIds">
          <TagSelect />
        </Form.Item>
        <Form.Item label="经办人" name="processorId">
          <UserSelect defaultOptionName={"经办人"} />
        </Form.Item>
        <Form.Item label="任务组" name="epicId">
          <EpicSelect defaultOptionName={"任务组"} />
        </Form.Item>
        <Form.Item label="类型" name="typeId">
          <TypeSelect />
        </Form.Item>
      </Form>
    </Modal>
  );
};
