import React, { ReactNode } from "react";
import {
  DragDropContext,
  Draggable,
  DraggableProps,
  DraggableProvided,
  DraggableStateSnapshot,
  Droppable,
  DroppableProps,
  DroppableProvided,
  DroppableProvidedProps,
} from "react-beautiful-dnd";

export const Drop = ({
  children,
  ...props
}: Omit<DroppableProps, "children"> & { children: ReactNode }) => {
  return (
    <Droppable {...props}>
      {(provided: DroppableProvided) => {
        if (React.isValidElement(children)) {
          return React.cloneElement(children, {
            ...provided.droppableProps,
            ref: provided.innerRef,
            provided,
          });
        } else {
          return <div></div>;
        }
      }}
    </Droppable>
  );
};

type Other = { provided: DroppableProvided } & DroppableProvidedProps;
type E = HTMLDivElement;

export const DropChild = React.forwardRef<
  E,
  Partial<Other> & React.HTMLAttributes<E>
>(({ children, ...props }, ref) => (
  <div ref={ref} {...props}>
    {children}
    {/*placeholder 是用来撑住高度的*/}
    {props.provided?.placeholder}
  </div>
));

export const Drag = ({
  children,
  ...props
}: Omit<DraggableProps, "children"> & { children: ReactNode }) => {
  return (
    <Draggable {...props}>
      {(provided: DraggableProvided) => {
        // TODO 这是一个很好地案例，用来讲不能在render里面setState
        if (React.isValidElement(children)) {
          return React.cloneElement(children, {
            ...provided.draggableProps,
            ...provided.dragHandleProps,
            ref: provided.innerRef,
          });
        } else {
          return <div></div>;
        }
      }}
    </Draggable>
  );
};
