import { useAuth } from "context/auth-context";
import { Button, Form, Input } from "antd";
import React from "react";
import { useAsync } from "utils/use-async";
import { OnFinish } from "unauthenticated-app/index";
import styles from "./unauthenticated-app.module.css";

export const Register = ({ onFinish }: { onFinish?: OnFinish }) => {
  const { run, isLoading } = useAsync(undefined, { throwOnError: true });
  const { register } = useAuth();

  const handleSubmit = async ({
    username,
    password,
    cpassword,
  }: {
    username: string;
    password: string;
    cpassword: string;
  }) => {
    if (password !== cpassword) {
      onFinish?.({ error: new Error("请确认两次输入的密码相同") });
      return;
    }
    try {
      await run(register?.({ username, password }) || Promise.resolve());
    } catch (error) {
      onFinish?.({ error });
    }
  };

  return (
    <Form
      name="register"
      initialValues={{ remember: true }}
      onFinish={handleSubmit}
      style={{ textAlign: "left" }}
    >
      <Form.Item
        name="username"
        rules={[{ required: true, message: "Please input username" }]}
      >
        <Input placeholder={"用户名"} />
      </Form.Item>

      <Form.Item
        name="password"
        rules={[{ required: true, message: "Please input password" }]}
      >
        <Input.Password placeholder={"密码"} />
      </Form.Item>

      <Form.Item
        name="cpassword"
        rules={[{ required: true, message: "Please confirm password" }]}
      >
        <Input.Password placeholder={"请确认密码"} />
      </Form.Item>

      <Form.Item>
        <Button
          loading={isLoading}
          className={styles.button}
          type="primary"
          htmlType="submit"
        >
          注册
        </Button>
      </Form.Item>
    </Form>
  );
};
