import React from "react";
// 替代 ts 中的 namespace
import * as auth from "auth-provider";
import { AuthForm } from "auth-provider";
import { User } from "types/user";
import { http } from "utils/http";
import { useAsync } from "utils/use-async";
import { useMount } from "utils";
import { useQueryClient } from "react-query";
import { Spin } from "antd";

async function bootstrapUser() {
  let user = null;
  const token = await auth.getToken();

  if (token) {
    const data: { user: User } = await http("me", { method: "get", token });
    user = data.user;
  }
  return user;
}

export const AuthContext = React.createContext<
  | {
      user: User | null;
      register: (user: AuthForm) => Promise<void>;
      login: (user: AuthForm) => Promise<void>;
      logout: () => Promise<void>;
    }
  | undefined
>(undefined);
AuthContext.displayName = "AuthContext";

export function AuthProvider(props: object) {
  const {
    data: user,
    stat,
    error,
    isLoading,
    isIdle,
    isError,
    isSuccess,
    run,
    setData,
  } = useAsync<User | null>();

  useMount(() => {
    run(bootstrapUser());
  });

  const queryClient = useQueryClient();

  const login = (form: AuthForm) =>
    auth.login(form).then((user) => setData(user));
  const register = (form: AuthForm) =>
    auth.register(form).then((user) => setData(user));

  // TODO 别忘了
  // queryCache.clear()
  const logout = () =>
    auth.logout().then(() => {
      queryClient.clear();
      setData(null);
    });

  const value = { user, login, logout, register };

  if (isLoading || isIdle) {
    return (
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          height: "100vh",
        }}
      >
        <Spin size={"large"} />
      </div>
    );
  }

  if (isError) {
    return <p style={{ color: "red" }}>{error?.message}</p>;
  }

  if (isSuccess) {
    return <AuthContext.Provider value={value} {...props} />;
  }

  throw new Error(`出现错误: ${stat}`);
}

export function useAuth() {
  const context = React.useContext(AuthContext);
  if (context === undefined) {
    throw new Error(`useAuth 必须在 AuthProvider 中使用`);
  }
  return context;
}
