import { useSearch } from "utils/url";

export const useTaskPatch = () => {
  const [searchParams, setSearchParams] = useSearch(["editingTaskId"]);
  const modalOpen = Boolean(searchParams.editingTaskId);

  const close = () =>
    setSearchParams({
      editingTaskId: ""
    });
  const startEdit = (id: number) =>
    setSearchParams({
      editingTaskId: String(id)
    });

  return {
    modalOpen,
    close,
    startEdit,
    editingId: Number(searchParams.editingTaskId)
  };
};
