import { QueryKey, useQueryClient } from "react-query";

export const useConfig = (
  queryKey: QueryKey,
  callback: (target: any, old: any[]) => any[]
) => {
  const queryClient = useQueryClient();
  return {
    onMutate: async (targetItem: any) => {
      await queryClient.cancelQueries(queryKey);
      const previousItems = queryClient.getQueryData(queryKey) || [];
      queryClient.setQueryData(queryKey, (old?: unknown[]) => callback(targetItem, old || []));
      return { previousItems };
    },
    onError: (err: Error, newItem: any, context: any) => {
      queryClient.setQueryData(queryKey, context?.previousItems);
    },
    onSettled: () => {
      queryClient.invalidateQueries(queryKey);
    }
  };
};

export const useDeleteConfig = (queryKey: QueryKey) => useConfig(queryKey, (targetItem, old) => old.filter(item => item.id !== targetItem.id));
export const useEditConfig = (queryKey: QueryKey) => useConfig(queryKey, (targetItem, old) => old.map(item => item.id === targetItem.id ? { ...item, ...targetItem } : item));
export const useAddConfig = (queryKey: QueryKey) => useConfig(queryKey, (targetItem, old) => [...old, targetItem]);
