import { useLocation, useParams, useSearchParams } from "react-router-dom";
import { useMemo } from "react";
import { cleanObject, subset } from "./index";
import { useProject } from "./project";
import qs from "qs";

// 下面这个可以在useQuery里面讲
// ts的泛型，要不然就全都让ts推断，要不然就全都指定，目前还没有好的方案：https://stackoverflow.com/a/55754981/12410906
export const useSearch = <K extends string>(keys: K[]) => {
  const [searchParams, setSearchParams] = useSearchParams();
  return [
// 不要再浪费时间了，就用any
    useMemo(() => subset(qs.parse(searchParams.toString()), keys) as { [key in K]: any }, [
      searchParams
    ]),

    // 这里不能直接用 <S>, 因为比如我们传入{age: '8'}, 希望也能用 {age: 8}
    // (params: Partial<S>) => {
    (params: Partial<{ [key in K]: unknown }>) => {
      const o = { ...Object.fromEntries(searchParams.entries()), ...params };
      return setSearchParams(cleanObject(o));
    },

    () => setSearchParams("")
  ] as const;
};

export const useProjectIdInUrl = () => {
  const { pathname } = useLocation();
  const id = pathname.match(/projects\/(\d+)?/)?.[1];
  return +(id || 0);
};

export const useProjectInUrl = () => {
  return useProject(useProjectIdInUrl());
};
