import { useHttp } from "./http";
import { useMutation, useQuery } from "react-query";
import { Epic } from "../types/epic";
import { useProjectIdInUrl, useSearch } from "./url";
import { Raw } from "types";
import { useAddConfig, useEditConfig } from "utils/use-query-default-options";

export const useEpicSearchParams = () => {
  return ({
    projectId: useProjectIdInUrl()
  });
};

export const useEpicsQueryKey = () => {
  return ["epics", useEpicSearchParams()];
};


export const useEpicsInProject = () => {
  const projectId = useProjectIdInUrl();
  return useEpics({ projectId });
};

export const useEpics = (params?: object) => {
  const client = useHttp();
  return useQuery<Epic[], Error>({
    queryKey: ["epics", params],
    queryFn: () => {
      return client("epics", { data: params });
    }
  });
};

export const useEpic = (id?: Raw) => {
  const client = useHttp();
  return useQuery<Epic>(
    ["epic", id],
    () => client(`epics/${id}`),
    {
      enabled: !!id
    });
};

export const useEditEpic = () => {
  const client = useHttp();
  return useMutation(
    (params: Partial<Epic>) =>
      client(`epics/${params.id}`, {
        data: params,
        method: "PATCH"
      }),
    useEditConfig(useEpicsQueryKey())
  );
};

export const useCreateEpic = () => {
  const client = useHttp();
  return useMutation(
    (params: Partial<Epic>) =>
      client(`epics`, {
        data: params,
        method: "POST"
      }),
    useAddConfig(useEpicsQueryKey())
  );
};


