import { useSearch } from "utils/url";
import { useEpic, useEpics } from "utils/epic";

export const useEpicPatch = () => {
  const [searchParams, setSearchParams] = useSearch(["editingEpicId", "creatingEpic"]);
  const modalOpen = Boolean(
    searchParams.editingEpicId || searchParams.creatingEpic
  );

  const { data: editingProject, isLoading } = useEpic(
    searchParams.editingEpicId
  );
  const isEditing = !!searchParams.editingEpicId;
  const initialValues = isEditing ? editingProject : undefined;

  const close = () =>
    setSearchParams({
      editingEpicId: "",
      creatingEpic: ""
    });
  const startEdit = (id: number) =>
    setSearchParams({
      editingEpicId: String(id)
    });
  const startCreate = () =>
    setSearchParams({
      creatingEpic: "true"
    });

  return {
    isLoading,
    modalOpen,
    initialValues,
    close,
    startEdit,
    startCreate,
    isEditing
  }
};
