import React from "react";
import { css, jsx } from "@emotion/react";
import { useUsers } from "utils/user";
import { IdSelect, SingleIdProp } from "components/id-select";

export const UserSelect = (props: SingleIdProp) => {
  const { data: users, isLoading } = useUsers();

  return (
    <IdSelect
      options={users}
      loading={isLoading}
      css={css`
        min-width: 13rem;
      `}
      {...props}
    />
  );
};
