/** @jsx jsx */
import { css, jsx } from "@emotion/react";
import React, { useEffect } from "react";
import { Button, Drawer, Form, Input, Spin, Skeleton } from "antd";
import { UserSelect } from "components/user-select";
import Title from "antd/es/typography/Title";
import { useForm } from "antd/es/form/Form";
import { ErrorMessage } from "components/lib";
import { useCreateEpic, useEditEpic, useEpicSearchParams } from "utils/epic";
import { useEpicPatch } from "screens/epic/use-epic-patch";
import { RangePicker } from "components/range-picker";
import dayjs, { Dayjs } from "dayjs";

// TODO 这里的代码写的不好，要改
export const DoEpicScreen = () => {
  const {
    modalOpen,
    close,
    initialValues,
    isEditing,
    isLoading: isLoadingProject,
  } = useEpicPatch();
  const {
    mutateAsync: edit,
    isLoading: editIsLoading,
    error: editError,
  } = useEditEpic();
  const {
    mutateAsync: create,
    isLoading: createIsLoading,
    error: createError,
  } = useCreateEpic();
  const loading = editIsLoading || createIsLoading;
  const error = editError || createError;
  const [form] = useForm();
  const search = useEpicSearchParams();

  const title = isEditing ? "编辑任务组" : "创建任务组";

  const closeModal = () => {
    close();
    form.resetFields();
  };

  const onFinish = async (values: any) => {
    const [start, end] = values.dateRange;
    const method = isEditing ? edit : create;
    await method({
      ...initialValues,
      ...values,
      start: start.toDate().getTime(),
      end: end.toDate().getTime(),
      ...search,
    });
    closeModal();
  };

  useEffect(() => {
    form.setFieldsValue(initialValues);
  }, [initialValues, form]);

  return (
    <Drawer
      forceRender={true}
      destroyOnClose={true}
      width={"100%"}
      onClose={closeModal}
      visible={modalOpen}
    >
      <div
        css={css`
          height: 80vh;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
        `}
      >
        {isLoadingProject ? (
          <Spin size={"large"} />
        ) : (
          <React.Fragment>
            <Title>{title}</Title>
            {error ? <ErrorMessage error={error} /> : null}
            <Form
              form={form}
              layout="vertical"
              css={css`
                width: 40rem;
              `}
              onFinish={onFinish}
            >
              <Form.Item
                label="任务组名称"
                name="name"
                rules={[{ required: true, message: "请输入任务组名称" }]}
              >
                <Input placeholder={"输入任务组名称"} />
              </Form.Item>

              <Form.Item label="备注" name="note">
                <Input />
              </Form.Item>

              <Form.Item name="personId" label={"负责人"}>
                <UserSelect defaultOptionName={"负责人"} />
              </Form.Item>

              <Form.Item name="dateRange" label={"起始日期"}>
                <RangePicker
                  ranges={{
                    今天: [dayjs(), dayjs()],
                    本月: [dayjs().startOf("month"), dayjs().endOf("month")],
                  }}
                />
              </Form.Item>

              <Form.Item
                css={css`
                  text-align: left;
                `}
              >
                <Button loading={loading} type="primary" htmlType="submit">
                  提交
                </Button>
              </Form.Item>
            </Form>
          </React.Fragment>
        )}
      </div>
    </Drawer>
  );
};
