import { useHttp } from "./http";
import { useQuery } from "react-query";
import { TaskType } from "../types/task-type";

export const useTags = () => {
  const client = useHttp();
  return useQuery<TaskType[]>({
    queryKey: ["tags"],
    queryFn: () => {
      return client("tags");
    },
  });
};
