/** @jsx jsx */
import { css, jsx } from "@emotion/react";
import React, { useEffect } from "react";
import { Button, Drawer, Form, Input, Spin, Skeleton } from "antd";
import { UserSelect } from "components/user-select";
import Title from "antd/es/typography/Title";
import { useCreateProject, useEditProject } from "utils/project";
import { useForm } from "antd/es/form/Form";
import { ErrorMessage } from "components/lib";
import { useDoProject } from "utils/use-do-project";

// TODO 这里的代码写的不好，要改
export const ProjectModalScreen = () => {
  const {
    modalOpen,
    close,
    initialValues,
    isEditing,
    isLoading: isLoadingProject
  } = useDoProject();
  const { mutateAsync: editProject, isLoading: editIsLoading, error: editError } = useEditProject();
  const { mutateAsync: createProject, isLoading: createIsLoading, error: createError } = useCreateProject();
  const loading = editIsLoading || createIsLoading;
  const error = editError || createError;
  const [form] = useForm();

  const title = isEditing ? "编辑项目" : "创建项目";

  const closeModal = () => {
    close();
    form.resetFields();
  };

  const onFinish = async (values: any) => {
    const method = isEditing ? editProject : createProject;
    await method(
      { ...initialValues, ...values }
      // { throwOnError: true }
    );
    closeModal();
  };

  useEffect(() => {
    form.setFieldsValue(initialValues);
  }, [initialValues, form]);

  return (
    <Drawer
      forceRender={true}
      destroyOnClose={true}
      width={"100%"}
      onClose={closeModal}
      visible={modalOpen}
    >
      <div
        css={css`
          height: 80vh;
          display: flex;
          flex-direction: column;
          align-items: center;
          justify-content: center;
        `}
      >
        {isLoadingProject ? (
          <Spin size={"large"} />
        ) : (
          <React.Fragment>
            <Title>{title}</Title>
            {error ? <ErrorMessage error={error} /> : null}
            <Form
              form={form}
              layout="vertical"
              css={css`
                width: 40rem;
              `}
              onFinish={onFinish}
            >
              <Form.Item
                label="名称"
                name="name"
                rules={[{ required: true, message: "请输入项目名" }]}
              >
                <Input placeholder={"输入项目名称"} />
              </Form.Item>

              <Form.Item
                label="部门"
                name="organization"
                rules={[{ required: true, message: "请输入部门名称" }]}
              >
                {/*<Skeleton.Input style={{ width: 200 }} active={true} />*/}
                <Input />
              </Form.Item>

              <Form.Item name="personId" label={"负责人"}>
                <UserSelect defaultOptionName={"负责人"} />
              </Form.Item>

              <Form.Item
                css={css`
                  text-align: right;
                `}
              >
                <Button loading={loading} type="primary" htmlType="submit">
                  提交
                </Button>
              </Form.Item>
            </Form>
          </React.Fragment>
        )}
      </div>
    </Drawer>
  );
};
