/** @jsx jsx */
import { css, jsx } from "@emotion/react";
import React, { useEffect, useState } from "react";
import { Button, Card, Divider } from "antd";
import { useDocumentTitle } from "utils";
import { Register } from "unauthenticated-app/register";
import { Login } from "unauthenticated-app/login";
import styles from "./unauthenticated-app.module.css";
import styled from "@emotion/styled";
import logo from "assets/logo.svg";
import left from "assets/left.svg";
import right from "assets/right.svg";

export type OnFinish = (param?: { error: Error | null }) => void;

const C = styled(Card)`
  width: 400px;
  min-height: 560px;
  padding: 32px 40px;
  border-radius: 3px;
  box-sizing: border-box;
  color: rgb(94, 108, 132);
  text-align: center;
  box-shadow: rgba(0, 0, 0, 0.1) 0px 0px 10px;
  margin: 0 auto;
`;

const Container = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  min-height: 100vh;
`;

const Background = styled.div`
  position: absolute;
  width: 100%;
  height: 100%;
  background-repeat: no-repeat, no-repeat;
  background-attachment: fixed, fixed;
  background-position: left bottom, right bottom;
  background-size: calc(((100vw - 400px) / 2) - 32px),
    calc(((100vw - 400px) / 2) - 32px), cover;
  background-image: url(${left}), url(${right});
`;

const Header = styled.header`
  background: url(${logo}) no-repeat center;
  padding: 5rem 0;
  background-size: 8rem;
  width: 100%;
`;

export const UnauthenticatedApp = () => {
  const [error, setError] = useState<Error | null>(null);
  const [isRegister, setIsRegister] = useState(false);
  useEffect(() => {
    setError(null);
  }, [isRegister]);

  useDocumentTitle("请登录或注册账号以继续");

  const onFinish: OnFinish = (param) => param && setError(param.error);

  return (
    <Container>
      <Header />

      <Background />
      <C className={styles.card}>
        <h2 className={styles.title}>{isRegister ? "请注册" : "请登录"}</h2>
        <div style={{ marginBottom: "20px" }}>
          {error ? (
            <Card
              className={styles.errorBoxCard}
              bodyStyle={{ padding: "16px", fontSize: "12px" }}
            >
              {error?.message}
            </Card>
          ) : (
            <div></div>
          )}
        </div>
        {isRegister ? (
          <Register onFinish={onFinish} />
        ) : (
          <Login onFinish={onFinish} />
        )}

        <Button className={styles.button}>查看文档</Button>
        <Button className={styles.button}>查看课程</Button>
        <Divider />
        {isRegister ? (
          <a className={styles.footerText} onClick={() => setIsRegister(false)}>
            已经有账号了？直接登录
          </a>
        ) : (
          <a className={styles.footerText} onClick={() => setIsRegister(true)}>
            没有账号？注册新账号
          </a>
        )}
      </C>
    </Container>
  );
};
