import { useSearch } from "utils/url";
import { useProject } from "utils/project";

export const useDoProject = () => {
  const [searchParams, setSearchParams] = useSearch(["editingProjectId", "creatingProject"]);
  const modalOpen = Boolean(
    searchParams.editingProjectId || searchParams.creatingProject
  );

  const { data: editingProject, isLoading } = useProject(
    searchParams.editingProjectId
  );
  const isEditing = !!searchParams.editingProjectId;
  const initialValues = isEditing ? editingProject : undefined;

  const close = () =>
    setSearchParams({
      editingProjectId: "",
      creatingProject: ""
    });
  const startEdit = (id: number) =>
    setSearchParams({
      editingProjectId: String(id)
    });
  const startCreate = () =>
    setSearchParams({
      creatingProject: "true"
    });

  return {
    isLoading,
    modalOpen,
    initialValues,
    close,
    startEdit,
    startCreate,
    isEditing
  }
}
