//  模拟 firebase, netlify, 或者 auth0's 服务

import { User } from "types/user";

const localStorageKey = "__auth_provider_token__";

export type AuthForm = {
  username: string;
  password: string;
};

async function getToken() {
  return window.localStorage.getItem(localStorageKey);
}

function handleUserResponse({ user }: { user: User }) {
  window.localStorage.setItem(localStorageKey, user.token || "");
  return user;
}

function login({ username, password }: AuthForm) {
  return http<{ user: User }>("login", { username, password }).then(
    handleUserResponse
  );
}

function register({ username, password }: AuthForm) {
  return http<{ user: User }>("register", { username, password }).then(
    handleUserResponse
  );
}

async function logout() {
  window.localStorage.removeItem(localStorageKey);
}

const authURL = process.env.REACT_APP_API_URL;

// 讲讲后端抛错误的经验
async function http<R>(endpoint: string, data: object) {
  const config = {
    method: "POST",
    body: JSON.stringify(data),
    headers: { "Content-Type": "application/json" },
  };

  return window
    .fetch(`${authURL}/${endpoint}`, config)
    .then(async (response) => {
      const data = await response.json();
      if (response.ok) {
        return data as R;
      } else {
        return Promise.reject(data);
      }
    });
}

export { getToken, login, register, logout, localStorageKey };
