import React, { useEffect, useState } from "react";
import { Card, Input, Spin } from "antd";
import { Task } from "../types/task";
import { useCreateTask } from "utils/task";

export const CreateTask: React.FC<Partial<Task>> = (props) => {
  const [name, setName] = useState("");
  const { mutateAsync: createTask } = useCreateTask();
  const [inputMode, setInputMode] = useState(false);

  const submit = () => {
    setInputMode(false);
    setName("");
    createTask({ ...props, name });
  };

  useEffect(() => {
    if (!inputMode) {
      setName("");
    }
  }, [inputMode]);


  if (!inputMode) {
    return <div style={{ paddingLeft: "0.5rem", paddingTop: "0.5rem" }} onClick={() => setInputMode(!inputMode)}>
      +创建事务
    </div>;
  }

  return (
    <Card>
      <Input
        onBlur={() => setInputMode(false)}
        placeholder={"需要做些什么?"}
        autoFocus={true}
        onPressEnter={submit}
        value={name}
        onChange={(event) => setName(event.target.value)}
      />
    </Card>
  );
};
