import { useAuth } from "context/auth-context";
import { AuthForm } from "auth-provider";
import { Button, Form, Input } from "antd";
import React from "react";
import { useAsync } from "utils/use-async";
import { OnFinish } from "unauthenticated-app/index";
import styles from "./unauthenticated-app.module.css";

export const Login = ({ onFinish }: { onFinish?: OnFinish }) => {
  const { isLoading, run } = useAsync(undefined, { throwOnError: true });
  const { login } = useAuth();

  const handleSubmit = async (values: AuthForm) => {
    try {
      await run(login?.(values) || Promise.resolve());
    } catch (error) {
      onFinish?.({ error });
    }
    onFinish?.();
  };

  return (
    <Form name="login" onFinish={handleSubmit}>
      <Form.Item
        name="username"
        rules={[{ required: true, message: "Please input your username!" }]}
      >
        <Input placeholder={"用户名"} />
      </Form.Item>
      <Form.Item
        name="password"
        rules={[{ required: true, message: "Please input your password!" }]}
      >
        <Input.Password placeholder={"密码"} />
      </Form.Item>

      <Form.Item>
        <Button
          className={styles.button}
          loading={isLoading}
          type="primary"
          htmlType="submit"
        >
          登录
        </Button>
      </Form.Item>
    </Form>
  );
};
